using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tool that fetches data from an external API using an injected HttpClient.
/// </summary>
internal class ApiFetchTool(HttpClient httpClient)
{
    [McpServerTool]
    [Description("Fetches JSON data from the specified URL and returns it as a formatted string.")]
    public async Task<string> FetchJson(
        [Description("The URL to fetch JSON data from")] string url)
    {
        using var response = await httpClient.GetAsync(url);
        response.EnsureSuccessStatusCode();

        using var stream = await response.Content.ReadAsStreamAsync();
        var json = await JsonSerializer.DeserializeAsync<JsonElement>(stream);

        return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol;
using ModelContextProtocol.Server;

/// <summary>
/// MCP prompt template that produces a summarization request for the given text.
/// </summary>
internal class SummarizationPrompt
{
    [McpServerPrompt]
    [Description("Generates a prompt that asks an LLM to summarize the provided text.")]
    public static ChatMessage Summarize(
        [Description("The text to summarize")] string text,
        [Description("Desired maximum length (e.g. '2 sentences', '100 words')")] string maxLength = "2 sentences")
    {
        return new ChatMessage(
            ChatRole.User,
            $"Summarize the following text in at most {maxLength}.\n\n{text}");
    }
}

