using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// Send ALL log output to stderr so it never corrupts the stdio JSON-RPC stream on stdout.
builder.Logging.AddConsole(o => o.LogToStandardErrorThreshold = LogLevel.Trace);

// Register a named HttpClient for the API-fetch tool.
builder.Services.AddHttpClient<ApiFetchTool>();

// Register MCP server with stdio transport, tools, and prompts.
builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithTools<RandomNumberTools>()
    .WithTools<ApiFetchTool>()
    .WithPrompts<SummarizationPrompt>();

await builder.Build().RunAsync();

